QueryScript.Source:
import sailpoint.object.QueryOptions;
import sailpoint.object.Filter;
import sailpoint.object.IdentityRequest;
import sailpoint.object.Identity;



List requestTypes = new ArrayList();
// requestTypes.add("WBLeaver");
// requestTypes.add("IFCLeaver");

requestTypes.add("Lifecycle");
//requestTypes.add("AccessRequest");

// Filter LeaverFilters = Filter.and(Filter.in("type" ,requestTypes) ,Filter.subquery("targetId", Identity.class, "id", Filter.ignoreCase(Filter.eq("correlated", false))));
Filter LeaverFilters = Filter.in("type" ,requestTypes);
QueryOptions qo = new QueryOptions();
qo.add(LeaverFilters);
return qo;

