import sailpoint.object.Identity;


String name= null;
if(null != value)
{
Identity id = context.getObjectById(Identity.class, value);
if(null != id)
{
name= id.getName();
}
}
return name;

import sailpoint.object.Identity;

String firstName= null;
if(null != value)
{

Identity id = context.getObjectById(Identity.class, value);
if(null != id)
{
firstName = id.getFirstname()!=null?id.getFirstname():id.getAttribute("firstname");

}
}
return firstName;

import sailpoint.object.Identity;

String lastname= null;
if(null != value)
{
Identity id = context.getObjectById(Identity.class, value);
if(null != id)
{
lastname = id.getLastname()!=null?id.getLastname():id.getAttribute("lastname");
}
}
return lastname;

import sailpoint.object.Filter;
import sailpoint.object.AuditEvent;
import sailpoint.object.*;




String name= null;
if(null != value)
{
Identity id = context.getObjectById(Identity.class, value);
if(null != id)
{
name= id.getName();
}
}

Filter filter = Filter.and(Filter.eq("target", "Identity:"+name),Filter.eq("action", "identityLifecycleEvent"),Filter.eq("string1", "LEAVER FEATURE"));

log.error(" name : "+name+"    "+filter);

//Filter filter = Filter.and(Filter.eq("target", "Identity:"+name),Filter.eq("action", "identityLifecycleEvent"));
AuditEvent event = context.getUniqueObject(AuditEvent.class,filter);
log.error(" event : "+event.toXml());

String eventname = event!=null?event.getString1():"";

return eventname;
